FROM account_balances
WHERE account_id = #{accountId}

mapper.update:
UPDATE account_balances
SET held = held + #{amount}
WHERE account_id = #{accountId}
  AND balance - held >= #{amount}

UPDATE account_balances
SET held = held - #{amount}
WHERE account_id = #{accountId}
  AND held >= #{amount}
